        "Long-horizon learner outcomes (learning retention, behaviour change)"
      ]
    },
    "P": {
      "name": "Population / participants",
      "intrinsic": "Three persona-driven simulated learners: novice-curious (yes/no questions), skeptical-engineer (factual questions), fatigued-returner (short messages, wraps early). Plus 7 hand-authored gold transcripts (4 positive, 3 negative cases).",
      "extrinsic": "≥ 3 university students outside the project team, recruited for a 15-minute session each."
    },
    "H": {
      "name": "How it was evaluated",
